#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_LEN 105
typedef struct {
    char name[MAX_LEN];
    int age;
} Person;
void introduce(Person *p) {
    printf("Hello, my name is %s and I am %d years old.\n", p->name, p->age);
}
typedef struct {
    Person base;
    char student_id[MAX_LEN];
    char major[MAX_LEN];
} Student;
void study(Student *s) {
    printf("%s is studying %s.\n", s->base.name, s->major);
}
typedef struct {
    Person base;
    char employee_id[MAX_LEN];
    char subject[MAX_LEN];
} Teacher;
void teach(Teacher *t) {
    printf("%s is teaching %s.\n", t->base.name, t->subject);
}
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        Student s;
        Teacher t;
        // student
        fgets(s.base.name, MAX_LEN, stdin);
        s.base.name[strcspn(s.base.name, "\n")] = '\0';
        scanf("%d", &s.base.age);
        getchar();
        fgets(s.student_id, MAX_LEN, stdin);
        s.student_id[strcspn(s.student_id, "\n")] = '\0';
        fgets(s.major, MAX_LEN, stdin);
        s.major[strcspn(s.major, "\n")] = '\0';
        // teacher
        fgets(t.base.name, MAX_LEN, stdin);
        t.base.name[strcspn(t.base.name, "\n")] = '\0';
        scanf("%d", &t.base.age);
        getchar();
        fgets(t.employee_id, MAX_LEN, stdin);
        t.employee_id[strcspn(t.employee_id, "\n")] = '\0';
        fgets(t.subject, MAX_LEN, stdin);
        t.subject[strcspn(t.subject, "\n")] = '\0';
        // output
        introduce(&s.base);
        study(&s);
        introduce(&t.base);
        teach(&t);
    }
    return 0;
}

